			var g_rmode = 'WORK';
	var g_debug = false;

	var g_Texts = new Object();	  


function RefreshReport(pstrGroupName)
{ 
	var xmlFormCtrls = nmdGetFormCtrls();
	if (xmlFormCtrls == null) return;

	var xmlGroup = xmlFormCtrls.FindElement2("GROUP","cod", pstrGroupName);
	if (xmlGroup == null) return;


	//Genero la URL
	var URL="";

	switch(xmlGroup.GetAttr("d_param_1"))
	{
		case "URL":
			URL=xmlGroup.GetAttr("o_text");		
			break;

		case "NOMAD":
			URL="../../ReportViewer.aspx?"+xmlGroup.GetAttr("o_text");
			break;

		default:
			if (xmlGroup.GetAttr("d_param_1").substr(0,5)=="WIKI/")
			{               
				document.getElementById(xmlGroup.GetAttr("cod")).innerHTML=WikiToHTML(parent.GenerateReportText(xmlGroup.GetAttr("d_param_1").substr(5), g_xmlValues));
				return;
			} else
			if (xmlGroup.GetAttr("d_param_1").substr(0,5)=="TEXT/")
			{               
				document.getElementById(xmlGroup.GetAttr("cod")).innerHTML=parent.GenerateReportText(xmlGroup.GetAttr("d_param_1").substr(5), g_xmlValues);
				return;
			} else
				URL="../../ReportViewer.aspx?ut="+parent.GetProxy().UserToken()+"|report="+parent.GetProxy().AppName()+"."+xmlGroup.GetAttr("d_param_1").substr(0,xmlGroup.GetAttr("d_param_1").length-4)+"|"+xmlGroup.GetAttr("o_text");
			break;
	}                  

	if (URL=="") return;

	URL=Replace(URL,"\n","{#CHAR.AMP#}");
	URL=Replace(URL,"|","{#CHAR.AMP#}");

	//Cambios Basicos	 
 	while(URL.indexOf("{")!=-1)
 	{
 		preURL=URL.substr(0, URL.indexOf("{"));
 		varURL=URL.substr(preURL.length+1, URL.substring(preURL.length+1).indexOf("}"));
 		posURL=URL.substr(preURL.length+varURL.length+2);

 		URL=preURL+GetVariableString(varURL)+posURL;
 	}                    

 	document.getElementById(xmlGroup.GetAttr("cod")).src=URL;
}


function BindControls(pstrValues) {
	var xmlFormCtrls;
  var xmlMetadata;
  var xmlFile, xmlFiles;
	var xmlGroup;
	var xmlCtrl;
	var xmlVar;
	var xmlOpt;
	var objValue;
	var objCtrl;
	var objVar;

	g_xmlValues = new NomadXML(pstrValues);
	xmlFormCtrls = nmdGetFormCtrls();

	//Obtiene el estado de la variable debug
	g_debug = g_xmlValues.GetAttrBool("debug");

	//alert(g_xmlValues.FindElement("DATA").ToString());

	//Recorre los metadata de las variables y guarda:
	//- el elemento XML del metadata
	//- un array con los controles asociados a esa variable
	if (g_xmlValues != null) {

		g_cVars = new Array();
		if (g_xmlValues != null) {
			xmlMetadata = g_xmlValues.FindElement("METADATA");

			var xmlCtrl;

			//Recorre los grupos del Metadata
			for (xmlGroup = xmlMetadata.FirstChild(); xmlGroup != null; xmlGroup = xmlGroup.Next()) {

				strGroupName = xmlGroup.GetAttr("name");

				//Recorre las variables del grupo
				for (xmlVar = xmlGroup.FirstChild(); xmlVar != null; xmlVar = xmlVar.Next()) {

					//alert("variable " + strGroupName + "." + xmlVar.GetAttr("name"));
					objVar = new Object();
					objVar.VarName = strGroupName + "." + xmlVar.GetAttr("name");
					objVar.VarName = objVar.VarName.toUpperCase();
					objVar.xmlMetadata = xmlVar;
					objVar.xmlMetadataGrp = xmlGroup;
					objVar.Ctrls = null;

					if (xmlVar.GetAttr("type") == "enum") {
						objVar.Options = new Array();
						for (xmlOpt = xmlVar.FirstChild(); xmlOpt != null; xmlOpt = xmlOpt.Next()) {
							//Es un combo. Agrega los options
							objVar.Options[xmlOpt.GetAttr("val")] = xmlOpt.GetAttr("txt");
						}
					}

					g_cVars[objVar.VarName] = objVar;

				}
			}
		}		
	}


	//Recorre los controles del formulario, obtiene los valores y los Setea
	if (xmlFormCtrls != null) {

		//Recorre los grupos
		for (xmlGroup = xmlFormCtrls.FirstChild(); xmlGroup != null; xmlGroup = xmlGroup.Next()) {

      //Valida si es un grupo con GRILLA
      if (xmlGroup.GetAttr("c_var_group") != "") {
      	g_cVarsGrid[xmlGroup.GetAttr("c_var_group")] = xmlGroup.GetAttr("cod");
      	g_cGridVars[xmlGroup.GetAttr("cod")] = xmlGroup.GetAttr("c_var_group");
      }

			//Recorre los campos del grupo
			for (xmlCtrl = xmlGroup.FirstChild(); xmlCtrl != null; xmlCtrl = xmlCtrl.Next()) {

				//Agrega el control en el array de controles
				var objCtrl = new Object();
				objCtrl.GroupName = xmlGroup.GetAttr("cod");
				objCtrl.GroupType = xmlGroup.GetAttr("c_mode");

				objCtrl.VarName   = xmlCtrl.GetAttr("c_var");
				objCtrl.VarName   = objCtrl.VarName == "" ? null : objCtrl.VarName;
				objCtrl.VarType   = xmlCtrl.GetAttr("c_type");
				objCtrl.ParentVar = xmlCtrl.GetAttr("c_parent_field");

				objCtrl.CtrlName  = xmlCtrl.GetAttr("ctrl_name");
				objCtrl.CtrlLabel = xmlCtrl.GetAttr("label");
				objCtrl.CtrlMode  = xmlCtrl.GetAttr("c_mode");

				objCtrl.OnChange = xmlCtrl.GetAttr("onchange") == "1";
				objCtrl.OnValidate = xmlCtrl.GetAttr("onvalidate") == "1";

				//Agrega el control a la coleccion
				AddInCols(objCtrl);

				//Agrega el control a la lista de hijos de una variable
				AddVarChildren(objCtrl);
			}

			switch (xmlGroup.GetAttr("c_mode")) {
				case "MAIN":
					//Recorre los campos del grupo y setea los valores
					for (xmlCtrl = xmlGroup.FirstChild(); xmlCtrl != null; xmlCtrl = xmlCtrl.Next()) {

						//Sete el valor al control.
						//Obtiene el valor de la variable
						objValue = GetVariable(xmlCtrl.GetAttr("c_var"));

						//Obtiene nuevamente el control
						objCtrl = g_cCtrls[xmlCtrl.GetAttr("ctrl_name")];

						if (objValue || objCtrl.VarType == "text" || objValue == 0) {
							nmdSetCtrlValue(objCtrl.CtrlName, objValue);
						}
					}
					break;

				case "GRID":
					//Obtiene el count del child
					var x;
					var ChildCount = GetChildLength(xmlGroup.GetAttr("c_var_group"));

					//Recorre los child y hace los add a la grilla
					for (x=0; x!=ChildCount; x++) {
						nmdAddGridRow(xmlGroup.GetAttr("cod"));

						//Recorre los campos del grupo y setea los valores
						for (xmlCtrl = xmlGroup.FirstChild(); xmlCtrl != null; xmlCtrl = xmlCtrl.Next()) {

							//Sete el valor al control.
							//Obtiene el valor de la variable
							objValue = GetVariable(xmlCtrl.GetAttr("c_var"), x+1);

							//Obtiene nuevamente el control
							objCtrl = g_cCtrls[xmlCtrl.GetAttr("ctrl_name")];

							if (objValue || objCtrl.VarType == "text") {
								nmdSetCtrlValue(objCtrl.CtrlName, objValue, x+1);
							}
						}
					}
					break;       

				case "REPORT":                   
					RefreshReport(xmlGroup.GetAttr("cod"));
					break;

				case "BUT":
					break;
			}

		}

		//Recorre los posibles archivos adjuntos
		xmlFiles = g_xmlValues.FindElement("FILES"); 

		var htmlFiles = document.getElementById("filesTABLE");
		if (htmlFiles) {
			for (xmlFile = xmlFiles.FirstChild(); xmlFile!= null; xmlFile = xmlFile.Next()) {
				nmdAddFileToTable(xmlFile.GetAttr("id"), xmlFile.GetAttr("name"), xmlFile.GetAttr("size")); //FALTA EL SIZE
			}

		}

	}

}

//Setea un valor en un control
//Recibe un valor tipado
function nmdSetCtrlValue(pCod, pobjValue, pIndex) {
	var objCtrl;
	var htmlCtrl;
	var CtrlName;

	pCod = pCod.toUpperCase();	
	//Valida que exista el control
	objCtrl = g_cCtrls[pCod];
	if (objCtrl) {

		//Si es un valor de un child busca el item adecuado.
		CtrlName = pIndex ? objCtrl.CtrlName + "_" + pIndex : objCtrl.CtrlName;

		htmlCtrl = document.getElementById(CtrlName);


		switch (objCtrl.VarType) {
			case "string":
			case "text":
				htmlCtrl.value = pobjValue ? pobjValue : "";
				break;

			case "int":
				htmlCtrl.value = int2text(pobjValue);
				break;

			case "double":
				htmlCtrl.value = number2text(pobjValue);
				break;

			case "date":
				htmlCtrl.value = pobjValue ? date2text(pobjValue) : "";
				break;

			case "bool":
				htmlCtrl.checked = pobjValue ? pobjValue : false;
				break;

			case "enum":
				htmlCtrl.value = pobjValue ? pobjValue.Value : "";
				break;

			case "fk":
				htmlCtrl.value = pobjValue ? pobjValue.Desc : "";
				break;

			case "file": alert("nmdSetCtrlValue file no implementado"); break;

		}

	}
}


//Retorna un objeto tipo "Valor de combo"
function nmdText2ObjEnum(pobjHTML) {
	var strDesc;
	var objResult = new Object();

	if (pobjHTML) {
		objResult.Type  = "enum";
		objResult.Value = pobjHTML.value;
		objResult.Des   = pobjHTML.options[pobjHTML.selectedIndex].text;
	} else {
	}

	return objResult;
}



//Retorna un objeto tipo "Valor de combo"
function nmdGetObjEnum(pstrValue, pOptions) {
	return nmdGetObjValue(pstrValue, pOptions[pstrValue]);
}

//Retorna un objeto tipo VALOR y DESCRIPCION
function nmdGetObjValue(pstrValue, pstrDesc) {
	var objResult;

	objResult = new Object();
	objResult.Value = pstrValue;
	objResult.Desc  = pstrDesc;

	return objResult;
}



//Se llama cuando se selecciona una fila desde una Guia
function nmdSetFK(pVarName, pVal, pDes, pIndex, pElement) {
	var objResult;

	objResult = nmdGetObjValue(pVal, pDes);
	nmdSetFKResult(pElement);
	SetFK(pVarName, objResult, pIndex);
}


//Setea la bandera correspondiente indicando el estado del control
function nmdSetEnabled(pobjCtrl, pValue, pIndex) {
	var htmlCtrl;
	var arrHtmlCtrls;
	var x;
	var strCtrlName;
	var strHelpName;

	if (pobjCtrl) {

		switch (pobjCtrl.GroupType) {
			case "MAIN":
			case "GRID":

				strCtrlName = pIndex ? (pobjCtrl.CtrlName + "_" + pIndex) : pobjCtrl.CtrlName;
				if (pIndex) {
					strCtrlName = pobjCtrl.CtrlName + "_" + pIndex;
					strHelpName = pobjCtrl.CtrlName + "_help_" + pIndex; 
				} else {
					strCtrlName = pobjCtrl.CtrlName;
					strHelpName = pobjCtrl.CtrlName + "_help"; 
				}


				switch (pobjCtrl.VarType) {
					case "string":
					case "int":
					case "text":
					case "double":
					case "bool":
					case "enum": 
						htmlCtrl = document.getElementById(strCtrlName);
						if (htmlCtrl) htmlCtrl.setAttribute("nmd-dis", pValue ? "0" : "1");
						break;

					case "date":
						htmlCtrl = document.getElementById(strCtrlName);
						if (htmlCtrl) htmlCtrl.setAttribute("nmd-dis", pValue ? "0" : "1");

					case "fk":
						arrHtmlCtrls = document.getElementsByName(strHelpName);
						for (x=0; x!=arrHtmlCtrls.length; x++) {
							htmlCtrl = arrHtmlCtrls[x];
							htmlCtrl.setAttribute("nmd-dis", pValue ? "0" : "1");
						}
						break;

					case "file": alert("nmdSetEnabled file no implementado"); break;

				}

				break;

			case "BUT":
				htmlCtrl = document.getElementById(pobjCtrl.CtrlName);
				if (htmlCtrl) htmlCtrl.setAttribute("nmd-dis", pValue ? "0" : "1");
				break;
		}		

		//Habilita o deshabilita realmente el control
		nmdSetActive(pobjCtrl, pValue, pIndex);

	}
}

//Habilita o deshabilita el control indicado
function nmdSetActive(pobjCtrl, pValue, pIndex) {
	var htmlCtrl;
	var arrHtmlCtrls;
	var x;
	var CtrlName, HelpName;
	var BanValue;

	if (pobjCtrl) {

		switch (pobjCtrl.GroupType) {
			case "MAIN":
			case "GRID":

				CtrlName = pIndex ? (pobjCtrl.CtrlName + "_" + pIndex) : pobjCtrl.CtrlName;

				switch (pobjCtrl.VarType) {
					case "string":
					case "int":
					case "text":
					case "double":
					case "bool":
					case "enum":
						htmlCtrl = document.getElementById(CtrlName);
						if (htmlCtrl) {
							BanValue = !(htmlCtrl.getAttribute("nmd-dis") == "1"); 
							htmlCtrl.disabled = !(nmdAnd(BanValue, pValue));
							htmlCtrl.className = htmlCtrl.disabled ? "BoxD" : "Box";
						}
						break;

					case "date":
						htmlCtrl = document.getElementById(CtrlName);
						if (htmlCtrl) {
							BanValue = !(htmlCtrl.getAttribute("nmd-dis") == "1"); 
							htmlCtrl.disabled = !(nmdAnd(BanValue,pValue));
							htmlCtrl.className = htmlCtrl.disabled ? "BoxD" : "Box";
						}

					case "fk":

						HelpName = pobjCtrl.CtrlName + (pIndex ? ("_help_" + pIndex) : "_help");
						arrHtmlCtrls = document.getElementsByName(HelpName);
						for (x=0; x!=arrHtmlCtrls.length; x++) {
							htmlCtrl = arrHtmlCtrls[x];
							BanValue = !(htmlCtrl.getAttribute("nmd-dis") == "1"); 

							//htmlCtrl.disabled = !(nmdAnd(BanValue,pValue));

							SButtonChangeStyle(htmlCtrl, (nmdAnd(BanValue,pValue) ? "ENABLED":"DISABLED"));
						}
						break;

					case "file": alert("nmdSetEnabled file no implementado"); break;

				}

				break;

			case "BUT":
				htmlCtrl = document.getElementById(pobjCtrl.CtrlName);
				if (htmlCtrl) htmlCtrl.disabled = !pValue;
				break;
		}		

	}
}

