			//Scripts para la GRILLA

//Al hacer click en el HELP de los row de la grilla
function nmdOnGRIDHelpClick(phtmlHelp) {
	var strGridName;
	var htmlTable;

	if (phtmlHelp.disabled) return;

	//Busca la tabla principal de la grilla
	strGridName = Replace(phtmlHelp.id, "_help", "");
	htmlTable = document.getElementById(strGridName);

	//Determina que modo es el del HELP
	if (phtmlHelp.getAttribute("nmd-mode") == "A") {
		//Agrega un CHILD al XML de datos
		AddChildXML(htmlTable.getAttribute("nmdVarGroup"));

	} else {                           

		if (confirm("¿Está seguro que desea eliminar el registro?")) {
			//Elimina un CHILD al XML de datos
			DeleteChildXML(htmlTable.getAttribute("nmdVarGroup"), phtmlHelp.getAttribute("nmd-idx"));
		}
	}	

}

//Agrega un registro a la grilla
function nmdAddGridRow(pName) {
	var htmlTable, htmlProto;	
	var newRow, newCell;
	var x;
	var htmlProtoCell;
	var strGridMode;
	var htmlA, htmlImg;
	var strInnerTD;
	var RowsCount;

	//Obtiene la tabla y el row proto
	htmlTable = document.getElementById(pName);
	htmlProto = document.getElementById(pName + "_proto");

	strGridMode = htmlTable.getAttribute("nmdGridMode");

	//Crea el nuevo ROW
	newRow = htmlTable.insertRow(htmlTable.rows.length-1);
	newRow.className = htmlProto.className;

	RowsCount = htmlTable.rows.length-3;

	//Recorre los TDs del proto y se los agrega al nuevo Row
	for (x = 0; Compare(x, htmlProto.cells.length) == -1; x++) {
		htmlProtoCell = htmlProto.cells[x];

		newCell = newRow.insertCell(-1);
		strInnerTD = htmlProtoCell.innerHTML;

		//alert("strInnerTD ANTES " + strInnerTD)

		if (htmlProtoCell.getAttribute("nmdCtrlName") != "") {
			//Realiza los reemplazos de los nombres de los controles
			strInnerTD = Replace(strInnerTD, ' id="' + htmlProtoCell.getAttribute("nmdCtrlName") + '_help"',   ' id="' + htmlProtoCell.getAttribute("nmdCtrlName") + "_help_" + RowsCount + '"');
			strInnerTD = Replace(strInnerTD, ' name="' + htmlProtoCell.getAttribute("nmdCtrlName") + '_help"', ' name="' + htmlProtoCell.getAttribute("nmdCtrlName") + "_help_" + RowsCount + '"');
			strInnerTD = Replace(strInnerTD, ' id=' + htmlProtoCell.getAttribute("nmdCtrlName") + '_help',     ' id="' + htmlProtoCell.getAttribute("nmdCtrlName") + "_help_" + RowsCount + '"');
			strInnerTD = Replace(strInnerTD, ' name=' + htmlProtoCell.getAttribute("nmdCtrlName") + '_help',   ' name="' + htmlProtoCell.getAttribute("nmdCtrlName") + "_help_" + RowsCount + '"');

			strInnerTD = Replace(strInnerTD, ' id="' + htmlProtoCell.getAttribute("nmdCtrlName") + '"',        ' id="' + htmlProtoCell.getAttribute("nmdCtrlName") + "_" + RowsCount + '"');
			strInnerTD = Replace(strInnerTD, ' name="' + htmlProtoCell.getAttribute("nmdCtrlName") + '"',      ' name="' + htmlProtoCell.getAttribute("nmdCtrlName") + "_" + RowsCount + '"');
			strInnerTD = Replace(strInnerTD, ' id=' + htmlProtoCell.getAttribute("nmdCtrlName"),               ' id="' + htmlProtoCell.getAttribute("nmdCtrlName") + "_" + RowsCount + '"');
			strInnerTD = Replace(strInnerTD, ' name=' + htmlProtoCell.getAttribute("nmdCtrlName"),             ' name="' + htmlProtoCell.getAttribute("nmdCtrlName") + "_" + RowsCount + '"');

			strInnerTD = Replace(strInnerTD, ' nmd-idx="0"', ' nmd-idx="' + RowsCount + '"');
		}

		//alert("strInnerTD DESPUES " + strInnerTD)
		newCell.innerHTML = strInnerTD;
		newCell.className = htmlProtoCell.className;

		//Verifica el smallbutton de eliminar
		if (x==0) {
			if (strGridMode == "CT") {

				//Cambia el help
				htmlA = newCell.childNodes.item(0);
				htmlA.setAttribute("nmd-mode", "D");

				htmlImg = htmlA.childNodes.item(0);
				htmlImg.src = Replace(htmlImg.src, "table_add_n.gif", "table_delete_n.gif");
				htmlImg.src = Replace(htmlImg.src, "table_add_o.gif", "table_delete_n.gif");
				htmlImg.title = "Eliminar el registro";

			} else {
				newCell.innerHTML = " ";
			}
		}

	}

	//Llama al evento Onchange de la grilla
	nmdOnEvent(pName, "ONCHANGE", null, "ADDROW");
}

function nmdDeleteGridRow(pName, pIndex) {
	var htmlTable;	
	var VarGroup;
	var xmlFormCtrls, xmlGroup;
	var xmlCtrl;
	var xmlGroup;

	htmlTable = document.getElementById(pName);

 	if (htmlTable) {

		VarGroup = htmlTable.getAttribute("nmdVarGroup");

		//Rebindea la grilla
		var x;
		var ChildCount = GetChildLength(VarGroup);

		xmlFormCtrls = nmdGetFormCtrls();
		xmlGroup = xmlFormCtrls.FindElement2("GROUP", "cod", pName);

		//Recorre los child y hace los add a la grilla
		for (x=0; x!=ChildCount; x++) {

			//Recorre los campos del grupo y setea los valores
			for (xmlCtrl = xmlGroup.FirstChild(); xmlCtrl != null; xmlCtrl = xmlCtrl.Next()) {

				//Sete el valor al control.

				//Obtiene el valor de la variable
				objValue = GetVariable(xmlCtrl.GetAttr("c_var"), x+1);

				//Obtiene nuevamente el control
				objCtrl = g_cCtrls[xmlCtrl.GetAttr("ctrl_name")];
				nmdSetCtrlValue(objCtrl.CtrlName, objValue, x+1);
			}
		}

		//Borra el ultimo
		htmlTable.deleteRow(htmlTable.rows.length-2);

		//Llama al evento Onchange de la grilla
		nmdOnEvent(pName, "ONCHANGE", null, "DELROW");
	}

}

