//Pone en foco el control indicado
function nmdSetFocus(pCtrl, pIndex) {
	var objCtrl;
	var htmlCtrl;

	//Valida si le pasan el nombre del control o el objeto
	if (typeof(pCtrl) == "object") {
		objCtrl = pCtrl;
	} else {
		pCtrl = pCtrl.toUpperCase();	
		objCtrl = g_cCtrls[pCtrl];
	}

	//Valida que exista el control
	if (objCtrl) {

		htmlCtrl = document.getElementById(objCtrl.CtrlName);

		if (htmlCtrl) {

			switch (objCtrl.GroupType) {
				case "MAIN":
					switch (objCtrl.VarType) {
						case "string":
						case "int":
						case "text":
						case "double":
						case "date":
						case "bool":
						case "enum":
						case "fk":
							if (!htmlCtrl.disabled)
								htmlCtrl.focus();
							break;

						case "file": alert("nmdSetFocus file no implementado"); break;

					}

					break;

				case "GRID":
					//TODO:
					//alert("nmdSetFocus GRID no implementado");
					break;

				case "BUT":
					//TODO:
					//alert("nmdSetFocus BUT no implementado");
					break;
			}		
		}	
	}


}

//Se ejecuta al hacerse el onBlur del control
function nmdOnBlur(pobjHTML) {
	var objNewValue;
	var Index;
	var DoSetVariable = true;

	//Determina el tipo de valor
	switch (pobjHTML.getAttribute("nmd-type")) {
		case "string":
		case "text":

			objNewValue = pobjHTML.value;
			break;

		case "int":    objNewValue = text2int(pobjHTML.value); break;
		case "double": objNewValue = text2number(pobjHTML.value); break;
		case "date":   objNewValue = text2date(pobjHTML.value); break;
		case "bool":   objNewValue = pobjHTML.checked; break;
		case "enum":   objNewValue = nmdText2ObjEnum(pobjHTML); break;

		case "fk":     DoSetVariable = false; break;

		case "file":
			alert("nmdOnBlur file no implementado");
			break;

	}

	if (DoSetVariable) {
		SetVariable(pobjHTML.getAttribute("nmd-var"), objNewValue, parseInt(pobjHTML.getAttribute("nmd-idx"), 10));
	}

}

//Se ejecuta al hacerse el onclick del boton
function nmdOnClick(pobjHTML) {
	var strValue;
	var objCtrl;
	var strEventsResult;

	//Busca el control asociado al boton
	objCtrl = g_cCtrls[pobjHTML.id];
	if (objCtrl?false:true) {
		alert("No se econtro el botón '" + pobjHTML.id + "'");
		return;
	}

	//----------------------------------------------------------
	//Realiza las acciones de acuerdo al tipo de boton

	switch(objCtrl.CtrlMode) {
		case "CA": //Cancelar  --------------------------------------------------------------

			//4 - Avisa al form padre y cierra el reporte
			parent.CompleteEdit(g_xmlValues, objCtrl.CtrlMode);

			break;

		case "AC": //Aceptar  ---------------------------------------------------------------
		case "AE": //Aceptar y Esperar  -----------------------------------------------------

				//1 - Determina si existe un valor a setear. Solo setea variables de tipo MAIN
				if (pobjHTML.getAttribute("nmd-var") != "") {
					strValue = "" + pobjHTML.getAttribute("nmd-valvar");
					SetVariable(pobjHTML.getAttribute("nmd-var"), (strValue ? strValue : ""), null);
				}

				//2 - Ejecuta el "OnClick" del control  
				strEventsResult = nmdOnEvent(pobjHTML.id, "ONCLICK");
				if (strEventsResult != "") {
					alert(strEventsResult);
					return;
				}

				//3 - Ejecuta el "OnValidate" general del reporte
				strEventsResult = OnFormValidate();
				if (strEventsResult != "") {
					alert(strEventsResult);
					return;
				}

				//4 - Avisa al form padre y cierra el reporte
				parent.CompleteEdit(g_xmlValues, objCtrl.CtrlMode);
			break;

		case "AF": //Accion de Formulario  --------------------------------------------------
				//1 - Determina si existe un valor a setear. Solo setea variables de tipo MAIN
				if (pobjHTML.getAttribute("nmd-var") != "") {
					strValue = pobjHTML.getAttribute("nmd-valvar");
					SetVariable(pobjHTML.getAttribute("nmd-var"), (strValue ? strValue : ""), null);
				}

				//2 - Ejecuta el "OnClick" del control  
				nmdOnEvent(pobjHTML.id, "ONCLICK");

			break;

		case "GU": //Guardar  ---------------------------------------------------------------
		case "GD": //Guardar y Delegar  -----------------------------------------------------

				//1 - Determina si existe un valor a setear. Solo setea variables de tipo MAIN
				if (pobjHTML.getAttribute("nmd-var") != "") {
					strValue = pobjHTML.getAttribute("nmd-valvar");
					SetVariable(pobjHTML.getAttribute("nmd-var"), (strValue ? strValue : ""), null);
				}

				//2 - Ejecuta el "OnClick" del control  
				nmdOnEvent(pobjHTML.id, "ONCLICK");

				//4 - Avisa al form padre y cierra el reporte
				parent.CompleteEdit(g_xmlValues, objCtrl.CtrlMode);
			break;

		case "DL": //Delegar  ---------------------------------------------------------------
				//4 - Avisa al form padre y cierra el reporte
				parent.CompleteEdit(g_xmlValues, objCtrl.CtrlMode);

			break;
	}

}


//Se ejecuta cuando se hace click sobre el HELP de un FK
function nmdOnFKHelpClick(pobjHTML) {
	var objParentValue;
	var Value;
	var Index;

	if (pobjHTML.disabled) return;

	Index = parseInt(pobjHTML.getAttribute("nmd-idx"), 10);

	if (pobjHTML.getAttribute("nmd-parent") != "") {
		if (GetMajor(pobjHTML.getAttribute("nmd-varname")) == GetMajor(pobjHTML.getAttribute("nmd-parent"))) {
			objParentValue = GetVariable(pobjHTML.getAttribute("nmd-parent"), Index);
		} else {
			objParentValue = GetVariable(pobjHTML.getAttribute("nmd-parent"), 0);
		}

		if (objParentValue) {} else {return;}

	} else {
		objParentValue = null;
	}

	if (objParentValue) {

		//Prepara los parametros para llamar la guia
		if (nmdIsObject(objParentValue))
			Value = objParentValue.Value; //Es un FK, un Combo, etc
		else
			Value = objParentValue;

	} else {
		Value = "";
	}

	//Inhabilita todos los controles
	SetFormEnable(false);

	//Llama al Formulario para indicarle que levante la guia
	parent.OpenFKHelp(Value, pobjHTML.getAttribute("nmd-imclass"), Index, pobjHTML.getAttribute("nmd-varname"), g_debug, window);

}

//Se ejecuta cuando se hace click sobre el HELP de BORRADO de un FK
function nmdOnFKClearClick(pobjHTML) {
	var objParentValue;
