function nmdOnFILESDelClick(pobjHTML) {
	if (pobjHTML.disabled) return;

	if (!confirm("¿Esta seguro que desea eliminar el archivo?")) return;

	var FileId;

	FileId = Replace(pobjHTML.id, "DEL", "");	

	//Elimina el archivo del administrador de archivos
	nmdDElFileFromTable(FileId);

	//Elimina el archivo del XML
	DeleteXMLFile(FileId)

	return;

}

function nmdAddFile(pstrData) {
	var strFileId, strFileName;

	xmlNewFile = new NomadXML(pstrData);

	strFileId = xmlNewFile.GetAttr("id");
	strFileName = xmlNewFile.GetAttr("name");

	//Agrega el archivo en el administrador de archivos
	nmdAddFileToTable(strFileId, strFileName, ""); //Falta el SIZE

	//Agrega el archivo en el XML
	AddXMLFile(strFileId, strFileName, ""); //Falta el size

}

function nmdAddFileToTable(pFileId, pFileName, pSize) {
	var xmlNewFile;
	var objTR, objTD;
	var objTemp;
	var objProtoTD;
	var strInner, strFileType;

	objTR = document.getElementById("filesTR");
	objProtoTD = document.getElementById("filesTD"); 


	//Agrega un archivo
	objTD = objTR.insertCell(-1);

	strInner = objProtoTD.innerHTML;
	strInner = Replace(strInner, "XXIDXX", pFileId);

	//Setea el html
	objTD.innerHTML = strInner;

	//Obtiene el tipo de archivo
	strFileType = nmdGetFileType(pFileName);

	objTemp = document.getElementById(pFileId + "A");
	objTemp.style.backgroundImage = "url(" + Replace(objTemp.getAttribute("nmd-img"), "XXFILEXX", strFileType) + ")";

	objTemp = document.getElementById(pFileId + "TEXT");
	objTemp.innerHTML = nmdGetFileName(pFileName);

}

function nmdDElFileFromTable(pFileId) {
	var htmlTR, htmlTD, htmlTable;
	var x;

	htmlTR = document.getElementById("filesTR");

	for (x = 0; x!=htmlTR.cells.length; x++) {
		htmlTD = htmlTR.cells.item(x);
		htmlTable = htmlTD.firstChild;

		if (htmlTable.id == pFileId) {
			htmlTR.deleteCell(x-1);
			break;
		}
	}

}

function nmdOnFILESDownloadClick(pobjHTML) {
	var FileId;
	var objIFrame;

	if (pobjHTML.disabled) return;

	FileId = Replace(pobjHTML.id, "DO", "");	

	objIFrame = document.getElementById("filesIFR");
	objIFrame.src = "../../ToDownLoad.aspx?modo=DB" + String.fromCharCode(38) + "file_id=" + FileId + String.fromCharCode(38) + "class=NucleusWF.Base.Ejecucion.Archivos.HEAD";

	return;
}

//Retorna el tipo de archivo segun la extension
function nmdGetFileType(pFileName) {
	var strExt = pFileName.substr(pFileName.lastIndexOf(".") + 1);
	var strFileType;

  switch (strExt.toUpperCase()) {
		case "":
  		strFileType = "no32.gif";
  		break;

  	case "DOC": case "DOCX": case "ODF": case "DOT": case "ODF": case "DOCM": case "DOTM": case "DOTX": case "WPD": case "RTF":
  		strFileType = "doc32.gif";
  		break;

  	case "AVI": case "MPG": case "MOV": case "MP4": case "ASX": case "FLV": case "3GP": case "MKV":
  		strFileType = "avi32.gif";
  		break;

  	case "EXE": case "COM": case "BAT":
  		strFileType = "exe32.gif";
  		break;

  	case "BMP": case "TIF": case "JPG":  case "GIF": case "PNG":
  		strFileType = "img32.gif";
  		break;

  	case "MP3": case "WAV": case "OGG": case "WMA": case "AC3": case "MID": case "AIF":
  		strFileType = "mp332.gif";
  		break;

  	case "PDF":
  		strFileType = "pdf32.gif";
  		break;

  	case "TXT": case "DAT": case "INF":
  		strFileType = "txt32.gif";
  		break;

  	case "XLS": case "CSV": case "ODS": case "XLT":  case "XLW": case "XLSX": case "XLSM": case "XLTX": case "XLTM":
  		strFileType = "xls32.gif";
  		break;

  	case "ZIP": case "RAR": case "7Z": case "ARJ": case "CAB": case "DEB": case "GZ": case "LZH": case "RPM": case "TAR": case "Z":
  		strFileType = "zip32.gif";
  		break;

  	case "BMP": case "TIF": case "JPG":  case "GIF": case "PNG":
  		strFileType = "img32.gif";
  		break;

  	case "XML":
  		strFileType = "xml32.gif";
  		break;

		default:
			strFileType = "bin32.gif";
  			break;			    		
  }

	return strFileType;
}

function nmdOnFileOver(pTable, pMode) {
	var htmlImg;
	var strId;

	if (pTable.getAttribute("nmd-dis") == "1") return;

	strId = pTable.id;

	pTable.style.backgroundColor = pMode ? "#D2DBE0" : "#F7F7F7";

	htmlImg = document.getElementById(strId + "DEL");
	if (htmlImg)
		htmlImg.style.display = pMode ? "inline" : "none";

	htmlImg = document.getElementById(strId + "DO");
	htmlImg.style.display = pMode ? "inline" : "none";

}

function nmdGetFileName(pName) {
	var maxL = 12;

	if (Compare(pName.length, maxL) == 1)
		return pName.substring(0, maxL) + "...";
	else 
		return pName;

}

//Habilita o inhabilita el administrador de archivos
function nmdFilesSetEnable(pMode) {
	var htmlTemp;
	var htmlTable, htmlTD, htmlTR;
	var x;
	var FileId;

	//Setea el boton de add
	htmlTemp = document.getElementById("filesAdd");
	if (htmlTemp) {
		if (pMode)
			htmlTemp.src = Replace(htmlTemp.src, "_d.gif", "_n.gif");
		else {
			htmlTemp.src = Replace(htmlTemp.src, "_n.gif", "_d.gif");
			htmlTemp.src = Replace(htmlTemp.src, "_o.gif", "_d.gif");
		}

		htmlTemp.disabled = !pMode;
	}

	htmlTR = document.getElementById("filesTR");
	if (htmlTR) {
		for (x = 0; x!=htmlTR.cells.length; x++) {
			if (x== 0) continue;

			htmlTD = htmlTR.cells.item(x);
			htmlTable = htmlTD.firstChild;

			htmlTable.setAttribute("nmd-dis", (pMode?"0":"1"));
		}

	}

}
